const now = new Date();
const subscribers = $input.all().map(i => i.json);
const toSend = [];

for (const sub of subscribers) {
  if (sub.status !== 'confirmed' && sub.confirmed !== 'true' && sub.confirmed !== true) continue;

  const subscribedAt = new Date(sub.subscribed_at);
  const daysSince = Math.floor((now - subscribedAt) / (1000 * 60 * 60 * 24));
  const lastDrip = parseInt(sub.last_drip_day || '0', 10);

  // Drip schedule: Day 0 (welcome), Day 3 (tips), Day 7 (resources)
  let dripDay = null;
  let dripType = null;

  if (lastDrip < 0.5 && daysSince >= 0) {
    dripDay = 0;
    dripType = 'welcome';
  } else if (lastDrip < 3 && daysSince >= 3) {
    dripDay = 3;
    dripType = 'tips';
  } else if (lastDrip < 7 && daysSince >= 7) {
    dripDay = 7;
    dripType = 'resources';
  }

  if (dripDay !== null) {
    toSend.push({
      email: sub.email,
      name: sub.name || 'Subscriber',
      drip_day: dripDay,
      drip_type: dripType
    });
  }
}

if (toSend.length === 0) {
  return [{ json: { skip: true, message: 'No drips due' } }];
}

return toSend.map(s => ({ json: s }));

const item = $input.first().json;
const templates = {
  welcome: {
    subject: `Welcome aboard, ${item.name}!`,
    body: `<h2>Welcome to the newsletter!</h2><p>Hi ${item.name},</p><p>Thanks for confirming your subscription. Here's what to expect:</p><ul><li>Weekly insights and tips</li><li>Exclusive resources and guides</li><li>Early access to new content</li></ul><p>Stay tuned — your first tips are coming in a few days.</p>`
  },
  tips: {
    subject: `3 tips to get you started, ${item.name}`,
    body: `<h2>Quick Start Tips</h2><p>Hi ${item.name},</p><p>Here are 3 tips to get the most from your subscription:</p><ol><li><strong>Reply to any email</strong> — we read every response</li><li><strong>Star our emails</strong> — so they never go to spam</li><li><strong>Share with a friend</strong> — help us grow the community</li></ol><p>More great content coming your way soon!</p>`
  },
  resources: {
    subject: `Your resource pack, ${item.name}`,
    body: `<h2>Curated Resources</h2><p>Hi ${item.name},</p><p>As promised, here are some of our best resources:</p><ul><li><strong>Getting Started Guide</strong> — Everything you need to know</li><li><strong>Best Practices</strong> — Learn from our experience</li><li><strong>Community</strong> — Connect with other subscribers</li></ul><p>Thanks for being part of our community. Regular newsletters start from next week!</p>`
  }
};

const template = templates[item.drip_type] || templates.welcome;

return [{
  json: {
    ...item,
    subject: template.subject,
    body: template.body
  }
}];
